import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import reportWebVitals from './reportWebVitals';
import Navbar from './componentes/Navbar/navbar.js';
import Index from './componentes/index-fir-sec/index-fir-sec.js';
import { BrowserRouter, Route, Routes } from 'react-router-dom';
import Contacto from './componentes/contacto-page/contacto.js';
import Bebidas from './componentes/bebidas/bebidas.js';
import Burguers from './componentes/burguers/burguers.js';
import Combos from './combos.js';
import Productos from './productos.js';
import Footer from './componentes/footer/footer.js';
import Carrito from './carrito.js';



const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <BrowserRouter>

    <Navbar />
    <Routes>

      <Route path="/" element={<Index />} />
      <Route path="/Productos" element={<Productos />} />
      <Route path="/Productos/Combos" element={<Combos />} />
      <Route path="/Productos/Burguers" element={<Burguers />} />
      <Route path="/Productos/Bebidas" element={<Bebidas />} />
      <Route path="/Contacto" element={<Contacto />} />
      <Route path='/Carrito' element={<Carrito />} />
    </Routes>
    <Footer/>

  </BrowserRouter>
);


reportWebVitals();
